import json, os, sys
from urllib.request import Request, urlopen
from urllib.error import HTTPError

index_body = {
    "name": os.environ["INDEX_NAME"],
    "fields": [
        {"name": "id", "type": "Edm.String", "searchable": False, "filterable": True, "retrievable": True, "stored": True, "sortable": False, "facetable": False, "key": True},
        {"name": "title", "type": "Edm.String", "searchable": True, "filterable": False, "retrievable": True, "stored": True, "sortable": False, "facetable": False, "key": False},
        {"name": "sourceUrl", "type": "Edm.String", "searchable": False, "filterable": False, "retrievable": True, "stored": True, "sortable": False, "facetable": False, "key": False},
        {"name": "content", "type": "Edm.String", "searchable": True, "filterable": False, "retrievable": True, "stored": True, "sortable": False, "facetable": False, "key": False},
        {"name": "summary", "type": "Edm.String", "searchable": True, "filterable": False, "retrievable": True, "stored": True, "sortable": False, "facetable": False, "key": False},
        {"name": "type", "type": "Edm.String", "searchable": False, "filterable": True, "retrievable": True, "stored": True, "sortable": False, "facetable": False, "key": False},
        {"name": "createdAt", "type": "Edm.DateTimeOffset", "searchable": False, "filterable": True, "retrievable": True, "stored": True, "sortable": True, "facetable": False, "key": False},
        {"name": "contentVector", "type": "Collection(Edm.Single)", "searchable": True, "filterable": False, "retrievable": False, "stored": False, "sortable": False, "facetable": False, "key": False, "dimensions": 3072, "vectorSearchProfile": "vector-profile"}
    ],
    "similarity": {"@odata.type": "#Microsoft.Azure.Search.BM25Similarity"},
    "semantic": {
        "configurations": [{
            "name": "semantic-config",
            "prioritizedFields": {
                "titleField": {"fieldName": "title"},
                "prioritizedContentFields": [{"fieldName": "content"}, {"fieldName": "summary"}],
                "prioritizedKeywordsFields": []
            }
        }]
    },
    "vectorSearch": {
        "algorithms": [{"name": "hnsw-algo", "kind": "hnsw", "hnswParameters": {"metric": "cosine", "m": 4, "efConstruction": 400, "efSearch": 500}}],
        "profiles": [{"name": "vector-profile", "algorithm": "hnsw-algo", "vectorizer": "openai-vectorizer"}],
        "vectorizers": [{
            "name": "openai-vectorizer",
            "kind": "azureOpenAI",
            "azureOpenAIParameters": {
                "resourceUri": os.environ["OPENAI_RESOURCE_URI"],
                "deploymentId": "text-embedding-3-large",
                "apiKey": os.environ["OPENAI_API_KEY"],
                "modelName": "text-embedding-3-large"
            }
        }],
        "compressions": []
    }
}

url = f'https://{os.environ["SEARCH_SERVICE_NAME"]}.search.windows.net/indexes/{os.environ["INDEX_NAME"]}?api-version=2024-07-01'
data = json.dumps(index_body).encode('utf-8')
req = Request(url, data=data, method='PUT')
req.add_header('Content-Type', 'application/json')
req.add_header('api-key', os.environ['SEARCH_ADMIN_KEY'])

try:
    resp = urlopen(req)
    print(f'Index created successfully (HTTP {resp.status})')
    print(resp.read().decode('utf-8'))
except HTTPError as e:
    print(f'Failed to create index (HTTP {e.code})')
    print(e.read().decode('utf-8'))
    sys.exit(1)
PYEOF
